166	/** Render a discriminated variant: the discriminator radios + the selected branch's fields. */
167	function VariantSection({
168	  variant,
169	  locale,
170	  formId,
171	}: {
172	  variant: FormVariantSet;
173	  locale: Locale;
174	  formId: string;
175	}) {
176	  // The conform `/future` field metadata exposes no live `.value`, so read the
177	  // submitted discriminator from the live `FormData`, falling back to the field's
178	  // default (its `defaultValue` / repopulated `lastResult`) so the server renders
179	  // the same branch the client will — matching the `useFormData(... ?? default)`
180	  // idiom the hand-tuned `method` forms use. A discriminator with no default
181	  // (registration's `type`) renders no branch until the user selects one, exactly
182	  // as the registration form does today.
183	  const meta = useField<string>(variant.discriminator);
184	  const fallback =
185	    typeof meta.defaultValue === 'string' ? meta.defaultValue : undefined;
186	  const live = useFormData(
187	    formId,
188	    (formData) => formData.get(variant.discriminator),
189	    { fallback },
190	  );
191	  const selected = typeof live === 'string' ? live : fallback;
192	  const branch = variant.variants.find((v) => v.value === selected);
193	
194	  return (
195	    <>
196	      <RadioGroup name={variant.discriminator}>
197	        <Radios>
198	          {variant.options.map((option) => (
199	            <Radio key={option.value} value={option.value}>
200	              {project(option.label, locale)}
201	            </Radio>
202	          ))}
203	        </Radios>
204	        <FieldErrors />
205	      </RadioGroup>
206	      {branch
207	        ? branch.fields.map((field) => (
208	            <FieldControl
209	              key={field.name}
210	              field={field}
211	              prefix=""
212	              locale={locale}
213	            />
214	          ))
215	        : null}
216	    </>
217	  );
218	}
