269	/** One presence issue a struct-level predicate reports, at a field path. */
270	type PresenceIssue = {
271	  readonly path: ReadonlyArray<PropertyKey>;
272	  readonly issue: string;
273	};
274	
275	/**
276	 * The required `MessageKey` a presence-requirable LEAF emits when absent. A
277	 * `nestedGroup` (handled by {@link groupPresenceIssue}) and an `optionalText`
278	 * (never presence-required) are excluded from the input type — they have no
279	 * single required key to return.
280	 */
281	const requiredMessageOf = (
282	  field: Extract<FieldKind, { requiredMessage: MessageKey }>,
283	): string => field.requiredMessage;
284	
285	/**
286	 * The presence issue an ABSENT selected-variant `nestedGroup` surfaces: a real
287	 * key at the group's FIRST presence-requirable inner field path (e.g.
288	 * `['extra', <first required inner field>]`), mirroring the registration
289	 * oracle's `['extra', 'tos']` (`registration-schema.ts:274-279`) — a selected
290	 * attendee branch that omits the whole `extra` group is an error, not a success
291	 * (`make-impossible-states-unrepresentable`). An empty group (no presence-
292	 * requirable inner field) cannot anchor a key, so it imposes no group-level
293	 * presence — its own (absent) inner fields carry no requirement anyway.
294	 */
295	const groupPresenceIssue = (
296	  group: Extract<FieldKind, { _tag: 'nestedGroup' }>,
297	): PresenceIssue | undefined => {
298	  for (const inner of group.fields) {
299	    if (!isPresenceRequirableLeaf(inner)) continue;
300	    return { path: [group.name, inner.name], issue: requiredMessageOf(inner) };
301	  }
302	  return undefined;
303	};
304	
305	/**
306	 * A leaf whose PRESENCE a variant/group can require when its branch is selected:
307	 * everything except `optionalText` (empty-allowed), an `optional: true` leaf
308	 * (checkbox / scalar — legitimately absent), and a `nestedGroup` (its own
309	 * presence is anchored by {@link groupPresenceIssue}, not a single key). The
310	 * survivors all carry a `requiredMessage`, so the narrowed type is the input to
311	 * {@link requiredMessageOf}.
312	 */
313	const isPresenceRequirableLeaf = (
314	  field: FieldKind,
315	): field is Extract<FieldKind, { requiredMessage: MessageKey }> => {
316	  if (field._tag === 'optionalText' || field._tag === 'nestedGroup') {
317	    return false;
318	  }
319	  if ('optional' in field && field.optional === true) return false;
320	  return true;
321	};
322	
323	/**
324	 * The presence requirements a discriminated `variant` imposes on the SELECTED
325	 * branch's fields — at their own paths — collected (not aborted) so a payload
326	 * missing several branch fields surfaces them all at once, exactly as the
327	 * oracle's single accumulating struct filter does
328	 * (`registration-schema.ts:239-302`). A selected branch's leaf that is absent
329	 * emits the leaf's required key at `[name]`; a selected branch's absent
330	 * `nestedGroup` emits a real key at its first inner required field
331	 * ({@link groupPresenceIssue}). An off-variant field is never demanded.
332	 */
333	const variantPresenceIssues = (
334	  variant: FormVariantSet,
335	  value: Record<string, unknown>,
336	): ReadonlyArray<PresenceIssue> => {
337	  const selected = value[variant.discriminator];
338	  const branch = variant.variants.find((v) => v.value === selected);
339	  if (!branch) return [];
340	  const issues: Array<PresenceIssue> = [];
341	  for (const field of branch.fields) {
342	    if (field._tag === 'nestedGroup') {
343	      if (value[field.name] === undefined) {
344	        const issue = groupPresenceIssue(field);
345	        if (issue) issues.push(issue);
346	      }
347	      continue;
348	    }
349	    if (!isPresenceRequirableLeaf(field)) continue;
350	    if (value[field.name] === undefined) {
351	      issues.push({ path: [field.name], issue: requiredMessageOf(field) });
352	    }
353	  }
354	  return issues;
355	};
356	
357	// ---------------------------------------------------------------------------
358	// Cross-field rules
359	// ---------------------------------------------------------------------------
360	
361	/**
362	 * The presence requirement one `requiredWhenEquals` rule imposes: when the
363	 * `when` field's value is one of `equals`, the `target` field is required, and
364	 * an absent-OR-empty target emits `message` at the target's path. Mirrors the
365	 * `method`-gated email/phone requirement of `contact.tsx:91-109`.
366	 *
367	 * The "required" sense here is PRESENCE-and-non-emptiness, not mere
368	 * key-presence. The oracle gates `email` as `Schema.optional(Email)` where
369	 * `Email` enforces `isMinLength(1)`, so `{ method: 'email', email: '' }` is a
370	 * decode error, not a success: a visibly-blank required field must never be
371	 * representable as valid (`make-impossible-states-unrepresentable`). The
372	 * recommended modelling pairs this rule with an `optional: true` `email`/text
373	 * target (optional-at-key, non-empty-when-present), where the FIELD codec
374	 * already rejects a present `''` (and does so BEFORE this struct-level filter
375	 * runs, so no duplicate issue is reported); this predicate additionally rejects
376	 * the absent/empty target so the requirement holds even if a definition gates
377	 * an empty-permitting `optionalText` target.
378	 */
379	const rulePresenceIssue = (
380	  rule: CrossFieldRule,
381	  value: Record<string, unknown>,
382	): PresenceIssue | undefined => {
383	  const trigger = value[rule.when];
384	  const triggered =
385	    typeof trigger === 'string' && rule.equals.includes(trigger as never);
386	  const target = value[rule.target];
387	  const unsatisfied = target === undefined || target === '';
388	  return triggered && unsatisfied
389	    ? { path: [rule.target], issue: rule.message }
390	    : undefined;
391	};
392	
393	/**
394	 * The SINGLE struct-level presence filter for a definition: the variant's
395	 * selected-branch requirements plus every cross-field rule, accumulated into one
396	 * issue list. Composing one accumulating filter (rather than chaining a
397	 * `.check` per concern) matches the oracle's single struct-level
398	 * `Schema.makeFilter` and is REQUIRED for fidelity — chained `.check`s ABORT
399	 * after the first failing filter (Effect's default), so two unsatisfied rules
400	 * (the contact/volunteer `email`+`phone` pair) would surface only one. One
401	 * filter collecting all issues reproduces the oracle's "report multiple failures
402	 * at once" behaviour without depending on a non-default `errors: 'all'` decode.
403	 */
404	const makePresenceFilter = (definition: FormDefinition) =>
405	  Schema.makeFilter(
406	    (value: Record<string, unknown>) => {
407	      const issues: Array<PresenceIssue> = [];
408	      if (definition.variant) {
409	        issues.push(...variantPresenceIssues(definition.variant, value));
410	      }
411	      for (const rule of definition.rules ?? []) {
412	        const issue = rulePresenceIssue(rule, value);
413	        if (issue) issues.push(issue);
414	      }
415	      return issues.length === 0 ? undefined : issues;
416	    },
417	    { title: 'FormDefinition.presence' },
418	  );
419	
420	// ---------------------------------------------------------------------------
421	// definitionToSchema — compile a FormDefinition into a validating codec
422	// ---------------------------------------------------------------------------
423	
424	/**
425	 * Compile a `FormDefinition` into the Effect Schema codec that validates its
426	 * submissions. The common `fields` and the optional variant fields form one
427	 * `Schema.Struct`; a SINGLE struct-level presence filter
428	 * ({@link makePresenceFilter}) re-imposes the variant's selected-branch
429	 * requirements and every cross-field rule, accumulating all issues at their own
430	 * field paths. The struct's `Issue` tree feeds `formatSchemaResult` unchanged.
431	 * One accumulating filter (not a chain of `.check`s) is required so multiple
432	 * unsatisfied requirements all surface, matching the oracle's single struct
433	 * filter.
434	 */
435	export const definitionToSchema = (
436	  definition: FormDefinition,
437	): Schema.Codec<DecodedForm, Encoded> => {
438	  const fields: Record<string, Schema.Top> = buildStructFields(
439	    definition.fields,
440	  );
441	  if (definition.variant) {
442	    Object.assign(fields, buildVariantOptionalFields(definition.variant));
443	  }
444	
445	  const struct = Schema.Struct(fields).check(
446	    makePresenceFilter(definition) as never,
447	  );
448	  return struct as unknown as Schema.Codec<DecodedForm, Encoded>;
449	};
450	
451	/**
452	 * Decode an unknown submission payload against a `FormDefinition`. Returns a
453	 * `Result` whose failure channel is the Effect Schema `Issue` tree — paired with
454	 * `formatSchemaResult` in the generic action skeleton (Branch 6.2) to bucket
455	 * failures into conform's `{ formErrors, fieldErrors }`. Reuses `parseSchema`'s
456	 * contract (`decodeUnknownResult`) so the generated codec and the hand-written
457	 * siblings share one decode boundary.
458	 */
459	export const decodeForm = (
460	  definition: FormDefinition,
461	  payload: unknown,
462	): Result.Result<DecodedForm, Issue> =>
463	  Schema.decodeUnknownResult(definitionToSchema(definition))(payload);

